import java.util.concurrent.*;
import java.util.Random;

public class MultiThreadedMatrixMultiplication {
    public static void main(String[] args) {
        int size = 10;
        int numThreads = 4;

        Random random = new Random();
        int[][] matrixA = new int[size][size];
        int[][] matrixB = new int[size][size];

        // Initialize matrices
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                matrixA[i][j] = random.nextInt(10);
                matrixB[i][j] = random.nextInt(10);
            }
        }

        // Create a matrix product result
        int[][] result = new int[size][size];

        // Create a executor service
        ExecutorService executor = Executors.newFixedThreadPool(numThreads);

        // Task for each thread: compute a portion of the product
        for (int i = 0; i < numThreads; i++) {
            int start = i * (size / numThreads);
            int end = (i + 1) * (size / numThreads);
            if (i == numThreads - 1) {
                end = size;
            }

            // Task for thread i
            Runnable task = () -> {
                for (int k = 0; k < size; k++) {
                    for (int j = start; j < end; j++) {
                        result[start][j] += matrixA[start][k] * matrixB[k][j];
                    }
                }
            };

            executor.submit(task);
        }

        // Shutdown the executor
        executor.shutdown();

        // Print the result
        System.out.println("Matrix Product:");
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                System.out.print(result[i][j] + " ");
            }
            System.out.println();
        }
    }
}
