const crypto = require('crypto');
const { JSON3 } = require('json3');
const LRU = require('lru-cache');

// Define LRU cache with size constraints
const cache = new LRU({
  max: 100,
  ttl: 60 * 10, // 10 seconds
  encode: JSON3.stringify,
  decode: JSON3.parse
});

// Decorator function
function memoizeLRU(cacheSize, ttl) {
  return function(target, propertyKey, descriptor) {
    const originalMethod = descriptor.value;
    const cacheKey = (function(key) {
      return crypto.createHash('sha256').update(key).digest('hex');
    })(propertyKey);

    // Memoize function
    const memoizedFunction = function(...args) {
      const key = crypto.createHash('sha256').update(JSON.stringify(args)).digest('hex');
      const cachedResult = cache.get(key);
      if (cachedResult) return cachedResult;

      const result = originalMethod.apply(this, args);
      cache.set(key, result);
      return result;
    };

    // Handle circular references
    memoizedFunction.circular = true;

    // Set cache
    descriptor.value = memoizedFunction;

    return descriptor;
  };
}

// Example usage
