def exponential_smoothing(data, alpha):
    def stateful_closure(previous_state):
        def process(value):
            nonlocal previous_state
            new_state = alpha * value + (1 - alpha) * previous_state
            previous_state = new_state
            return new_state
        return process
    return stateful_closure

